// Java 25 exam prep - Mutable keys break hashing
// Learn: hashed lookups probe the bucket for the key's current hashCode.
import java.util.HashSet;
import java.util.Objects;
import java.util.Set;

class Tag {
  String name;
  Tag(String name) { this.name = name; }
  @Override public boolean equals(Object other) {
    return other instanceof Tag tag && Objects.equals(name, tag.name);
  }
  @Override public int hashCode() { return Objects.hash(name); }
}

Set<Tag> tags = new HashSet<>();
Tag urgent = new Tag("urgent");
tags.add(urgent);
urgent.name = "later";
// The stored entry still sits in the bucket chosen for hash("urgent").
System.out.println(tags.contains(new Tag("later")));
System.out.println(tags.contains(urgent));
